import numpy as np

def value_iteration(P: np.ndarray, R: np.ndarray, gamma: float, theta: float = 1e-6) -> tuple:
    n_states, n_actions, _ = P.shape
    V = np.zeros(n_states)

    while True:
        V_new = np.zeros(n_states)
        for s in range(n_states):
            q_values = np.array([R[s, a] + gamma * np.dot(P[s, a], V)
                                  for a in range(n_actions)])
            V_new[s] = np.max(q_values)

        delta = np.max(np.abs(V_new - V))
        V = V_new
        if delta < theta:
            break

    pi = np.array([np.argmax([R[s, a] + gamma * np.dot(P[s, a], V)
                               for a in range(n_actions)])
                   for s in range(n_states)], dtype=int)

    return V, pi
